mlc::String print_declarations(mlc::Array<std::shared_ptr<cpp_ast::CppDeclaration>> declarations) noexcept{return declarations.map([](std::shared_ptr<cpp_ast::CppDeclaration> declaration) mutable { return cpp_ast::print_decl(declaration); }).join(mlc::String(""));}

std::shared_ptr<cpp_ast::CppType> integer_type() noexcept{return std::make_shared<cpp_ast::CppType>(cpp_ast::CppTypeName(mlc::String("int")));}

